sys_script_include.script:
var FuegoFrenzy = Class.create();
FuegoFrenzy.prototype = {
	initialize: function() {
		//get FuegoFileService table name
		var fuego_tbl_name;
		var fuego_tbl = new GlideRecord('sys_db_object');
		var fuego_tbl_qry = 'label=FuegoFileService';
		fuego_tbl.addQuery(fuego_tbl_qry);
		fuego_tbl.query();
		if(fuego_tbl.next()){
			fuego_tbl_name = fuego_tbl.name.toString();
		}

		this.fuego_tbl_name = fuego_tbl_name;
	},

	//return the file in JSON
	FileServe: function(path){	
		var bdy,mimetype;	
		var kontent = new GlideRecord(this.fuego_tbl_name);
		var kontent_qry = 'active=true^path='+path;
		kontent.addQuery(kontent_qry);
		kontent.query();
		if(kontent.next()){
			var nt = {};		
			nt.mimetype = kontent.mime_type.toString();
			nt.bdy = kontent.content.toString();
			return JSON.stringify(nt);
		}	
	},


	type: 'FuegoFrenzy'
};
